
const imageUrlPairs = [{"image":"data:image/png;base64,","url":"https://mlverse.github.io/luz/"},{"image":"data:image/png;base64,","url":"https://torch.mlverse.org/docs/"},{"image":"data:image/png;base64,","url":"https://mlverse.github.io/torchdatasets/"},{"image":"data:image/png;base64,","url":"https://mlverse.github.io/hfhub/"},{"image":"data:image/png;base64,","url":"https://mlverse.github.io/safetensors/"},{"image":"data:image/png;base64,","url":"https://github.com/jtleek/scorcher"},{"image":"data:image/png;base64,","url":"https://mlverse.github.io/torchvision/"},{"image":"data:image/png;base64,","url":"https://mlverse.github.io/torchvisionlib/"},{"image":"data:image/png;base64,","url":"https://bips-hb.github.io/innsight/"},{"image":"data:image/png;base64,","url":"https://mlverse.github.io/tabnet/"},{"image":"data:image/png;base64,","url":"https://brulee.tidymodels.org/"},{"image":"data:image/png;base64,","url":"https://mlverse.github.io/tok/"},{"image":"data:image/png;base64,","url":"https://mlverse.github.io/minhub/"},{"image":"data:image/png;base64,","url":"https://github.com/bnosac/ETM"},{"image":"data:image/png;base64,","url":"https://mlverse.github.io/torchaudio/"},{"image":"data:image/png;base64,","url":"https://mlverse.github.io/tft/"},{"image":"data:image/png;base64,","url":"https://github.com/mlverse/torchwavelets"},{"image":"data:image/png;base64,","url":"https://josiahparry.github.io/torchgnn/"},{"image":"data:image/png;base64,","url":"https://github.com/ielbadisy/survdnn"},{"image":"data:image/png;base64,","url":"https://github.com/cornball-ai/tinytorch"}];
const darkMode = false;
const highlightMode = false;
const focusPackages = null;

document.addEventListener("DOMContentLoaded", function() {
  const container = document.getElementById("imageContainer");

  if (darkMode) {
    document.documentElement.style.setProperty("--bg-color", "#1a1a1a");
    document.documentElement.style.setProperty("--text-color", "#ffffff");
    document.documentElement.style.setProperty("--tile-bg", "#2a2a2a");
    document.documentElement.style.setProperty("--attribution-bg", "rgba(255, 255, 255, 0.1)");
    document.documentElement.style.setProperty("--link-color", "#66b3ff");
  } else {
    document.documentElement.style.setProperty("--bg-color", "#ffffff");
    document.documentElement.style.setProperty("--text-color", "#000000");
    document.documentElement.style.setProperty("--tile-bg", "#f0f0f0");
    document.documentElement.style.setProperty("--attribution-bg", "rgba(0, 0, 0, 0.1)");
    document.documentElement.style.setProperty("--link-color", "#0066cc");
  }

  if (highlightMode) {
    container.classList.add("highlight-mode");
  }

  if (focusPackages && focusPackages.length > 0) {
    container.classList.add("focus-mode");
  }

  imageUrlPairs.forEach((pair, index) => {
    const div = document.createElement("div");
    const img = document.createElement("img");

    img.src = pair.image;
    img.alt = "Hexagon Image " + (index + 1);

    // Add focus class if this package is in the focus list
    if (focusPackages && pair.package && focusPackages.includes(pair.package)) {
      div.classList.add("focused");
    }

    if (pair.url && typeof pair.url === "string") {
      const a = document.createElement("a");
      a.href = pair.url;
      a.target = "_blank";
      a.appendChild(img);
      div.appendChild(a);
    } else {
      div.appendChild(img);
    }

    container.appendChild(div);
  });
});

